import { useState } from "react";
import { Button, Flex } from "@radix-ui/themes";
import { useSuspenseQuery } from "@tanstack/react-query";
import {
  ColDef,
  GetRowIdParams,
  ICellRendererParams,
  RowClickedEvent,
  Theme,
  ValueFormatterParams,
} from "ag-grid-community";
import { AgGridReact } from "ag-grid-react";

import { PlusIcon } from "../../../../../infrastructure/ts/icons/PlusIcon";
import { RefreshCwIcon } from "../../../../../infrastructure/ts/icons/RefreshCwIcon";
import type { Account } from "../../../client/ts";
import { listAccountsApiAccountsGetOptions } from "../../../client/ts/@tanstack/react-query.gen";
import { AccountEditor } from "../editors/AccountEditor";

const columnDefs: ColDef<Account>[] = [
  {
    field: "created_at",
    headerName: "Created At",
    cellDataType: "dateTimeString",
    width: 250,
    sort: "desc",
  },
  {
    field: "id",
    headerName: "Account ID",
    width: 250,
  },
  {
    field: "name",
    headerName: "Name",
    width: 250,
  },
  {
    field: "stripe_customer_id",
    headerName: "Stripe Customer ID",
    width: 250,
    cellRenderer: ({ value }: ICellRendererParams<Account, string>) =>
      value ? (
        <a
          href={`https://dashboard.stripe.com/customers/${value}`}
          target="_blank"
          rel="noopener noreferrer"
          style={{ color: "var(--accent-11)" }}
          onClick={(e) => e.stopPropagation()}
        >
          {value}
        </a>
      ) : null,
  },
  {
    field: "owner",
    headerName: "Owner",
    width: 250,
    cellRenderer: ({ value }: ICellRendererParams<Account, string>) =>
      value ? (
        <a
          href={`mailto:${value}`}
          style={{ color: "var(--accent-11)" }}
          onClick={(e) => e.stopPropagation()}
        >
          {value}
        </a>
      ) : null,
  },
  {
    field: "priority",
    headerName: "Priority",
    width: 250,
    cellDataType: "number",
  },
  {
    field: "domains",
    headerName: "Domains",
    width: 250,
    valueFormatter: (params: ValueFormatterParams<Account, string[]>) =>
      params.value?.join(", ") ?? "",
  },
  {
    field: "members",
    headerName: "Members",
    width: 250,
    valueFormatter: (params: ValueFormatterParams<Account, string[]>) =>
      params.value?.join(", ") ?? "",
  },
];

function AccountTable({ theme }: { theme: Theme }) {
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [selectedAccount, setSelectedAccount] = useState<Account | null>(null);

  const {
    data: accounts,
    refetch,
    isFetching,
  } = useSuspenseQuery({
    ...listAccountsApiAccountsGetOptions(),
    refetchInterval: 30000,
    refetchOnMount: false,
  });

  const handleRowClick = (event: RowClickedEvent<Account>) => {
    setSelectedAccount(event.data ?? null);
    setIsEditorOpen(true);
  };

  const handleAdd = () => {
    setSelectedAccount(null);
    setIsEditorOpen(true);
  };

  return (
    <>
      <Flex direction="column" style={{ flex: 1, height: "100%" }}>
        <div style={{ flex: 1, minHeight: 0 }}>
          <AgGridReact
            theme={theme}
            rowData={accounts}
            columnDefs={columnDefs}
            defaultColDef={{
              sortable: true,
              filter: true,
              floatingFilter: true,
              resizable: true,
            }}
            getRowId={(params: GetRowIdParams<Account>) => params.data.id!}
            sideBar={{
              toolPanels: ["columns", "filters"],
            }}
            animateRows={true}
            cellSelection={true}
            enableCharts={true}
            enableCellTextSelection
            ensureDomOrder
            onRowClicked={handleRowClick}
            suppressNoRowsOverlay={true}
          />
        </div>
        <Flex
          p="2"
          justify="end"
          gap="2"
          style={{
            borderTop: "1px solid var(--gray-6)",
            backgroundColor: "var(--gray-2)",
          }}
        >
          <Button
            size="1"
            variant="soft"
            onClick={() => refetch()}
            loading={isFetching}
            style={{ width: 180 }}
          >
            <RefreshCwIcon size={14} />
            Refresh Accounts
          </Button>
          <Button
            size="1"
            variant="soft"
            onClick={handleAdd}
            style={{ width: 180 }}
          >
            <PlusIcon size={14} />
            Create Account
          </Button>
        </Flex>
      </Flex>
      <AccountEditor
        isOpen={isEditorOpen}
        onClose={() => setIsEditorOpen(false)}
        account={selectedAccount}
      />
    </>
  );
}

export default AccountTable;

import { Button, Flex, Tooltip } from "@radix-ui/themes";
import { useSuspenseQuery } from "@tanstack/react-query";
import {
  ColDef,
  GetRowIdParams,
  ICellRendererParams,
  Theme,
  ValueGetterParams,
} from "ag-grid-community";
import { AgGridReact } from "ag-grid-react";

import { PlusIcon } from "../../../../../infrastructure/ts/icons/PlusIcon";
import { RefreshCwIcon } from "../../../../../infrastructure/ts/icons/RefreshCwIcon";
import type { Usage } from "../../../client/ts";
import { listUsagesApiUsagesGetOptions } from "../../../client/ts/@tanstack/react-query.gen";
import { AccountCell } from "../cells/AccountCell";
import { PriceCell } from "../cells/PriceCell";
import { QuotaCell } from "../cells/QuotaCell";
import { SubscriptionCell } from "../cells/SubscriptionCell";

const columnDefs: ColDef<Usage>[] = [
  {
    headerName: "Account",
    valueGetter: (params: ValueGetterParams<Usage>) => params.data?.account.id,
    width: 250,
    cellRenderer: ({ value }: ICellRendererParams<Usage, string>) => (
      <AccountCell accountId={value} />
    ),
    sort: "desc",
  },
  {
    headerName: "Account ID",
    valueGetter: (params: ValueGetterParams<Usage>) => params.data?.account.id,
    width: 250,
    hide: true,
  },
  {
    headerName: "Subscription",
    valueGetter: (params: ValueGetterParams<Usage>) =>
      params.data?.subscription.id,
    width: 250,
    cellRenderer: ({ value }: ICellRendererParams<Usage, string>) => (
      <SubscriptionCell subscriptionId={value} />
    ),
  },
  {
    headerName: "Subscription ID",
    valueGetter: (params: ValueGetterParams<Usage>) =>
      params.data?.subscription.id,
    width: 250,
    hide: true,
  },
  {
    headerName: "Price",
    valueGetter: (params: ValueGetterParams<Usage>) => params.data?.price.id,
    width: 250,
    cellRenderer: ({ value }: ICellRendererParams<Usage, string>) => (
      <PriceCell priceId={value} />
    ),
  },
  {
    headerName: "Price ID",
    valueGetter: (params: ValueGetterParams<Usage>) => params.data?.price.id,
    width: 250,
    hide: true,
  },
  {
    headerName: "Quota",
    valueGetter: (params: ValueGetterParams<Usage>) => params.data?.quota?.id,
    width: 250,
    cellRenderer: ({ value }: ICellRendererParams<Usage, string>) => (
      <QuotaCell quotaId={value} />
    ),
  },
  {
    headerName: "Quota ID",
    valueGetter: (params: ValueGetterParams<Usage>) => params.data?.quota?.id,
    width: 250,
    hide: true,
  },
  {
    headerName: "Metric",
    valueGetter: (params: ValueGetterParams<Usage>) => params.data?.metric,
    width: 250,
  },
  {
    headerName: "Soft Limit",
    valueGetter: (params: ValueGetterParams<Usage>) =>
      params.data?.quota?.soft_limit ?? null,
    cellDataType: "number",
    width: 250,
  },
  {
    headerName: "Hard Limit",
    valueGetter: (params: ValueGetterParams<Usage>) =>
      params.data?.quota?.hard_limit ?? null,
    cellDataType: "number",
    width: 250,
  },
  {
    headerName: "Usage",
    valueGetter: (params: ValueGetterParams<Usage>) => params.data?.usage,
    cellDataType: "number",
    width: 250,
  },
  {
    headerName: "Usage (%)",
    valueGetter: (params: ValueGetterParams<Usage>) => {
      const usage = params.data?.usage ?? 0;
      const limit = params.data?.quota?.hard_limit ?? 0;
      return usage > 0 && limit > 0 ? usage / limit : 0;
    },
    valueFormatter: (params) => `${Math.round(params.value * 100)}%`,
    cellDataType: "number",
    width: 250,
  },
  {
    headerName: "Starts At",
    valueGetter: (params: ValueGetterParams<Usage>) =>
      params.data?.billing_period?.starts_at ?? null,
    cellDataType: "dateTimeString",
    width: 250,
  },
  {
    headerName: "Ends At",
    valueGetter: (params: ValueGetterParams<Usage>) =>
      params.data?.billing_period?.ends_at ?? null,
    cellDataType: "dateTimeString",
    width: 250,
  },
];

function UsageTable({ theme }: { theme: Theme }) {
  const {
    data: usages,
    refetch,
    isFetching,
  } = useSuspenseQuery({
    ...listUsagesApiUsagesGetOptions(),
    refetchInterval: 30000,
    refetchOnMount: false,
  });

  return (
    <Flex direction="column" style={{ flex: 1, height: "100%" }}>
      <div style={{ flex: 1, minHeight: 0 }}>
        <AgGridReact
          theme={theme}
          rowData={usages}
          columnDefs={columnDefs}
          defaultColDef={{
            sortable: true,
            filter: true,
            floatingFilter: true,
            resizable: true,
          }}
          getRowId={(params: GetRowIdParams<Usage>) =>
            `${params.data.account.id}-${params.data.subscription.id}-${params.data.metric}`
          }
          sideBar={{
            toolPanels: ["columns", "filters"],
          }}
          animateRows={true}
          cellSelection={true}
          enableCharts={true}
          enableCellTextSelection
          ensureDomOrder
          suppressNoRowsOverlay={true}
        />
      </div>
      <Flex
        p="2"
        justify="end"
        gap="2"
        style={{
          borderTop: "1px solid var(--gray-6)",
          backgroundColor: "var(--gray-2)",
        }}
      >
        <Button
          size="1"
          variant="soft"
          onClick={() => refetch()}
          loading={isFetching}
          style={{ width: 180 }}
        >
          <RefreshCwIcon size={14} />
          Refresh Usage
        </Button>
        <Tooltip content="Usage is reported via usage events">
          <Button size="1" variant="soft" disabled style={{ width: 180 }}>
            <PlusIcon size={14} />
            Create Usage
          </Button>
        </Tooltip>
      </Flex>
    </Flex>
  );
}

export default UsageTable;

