import { useCallback, useState } from "react";
import { Button, Flex } from "@radix-ui/themes";
import {
  useMutation,
  useQueryClient,
  useSuspenseQuery,
} from "@tanstack/react-query";
import {
  ColDef,
  GetRowIdParams,
  ICellRendererParams,
  Theme,
} from "ag-grid-community";
import { AgGridReact } from "ag-grid-react";

import { CheckIcon } from "../../../../../infrastructure/ts/icons/CheckIcon";
import { PlusIcon } from "../../../../../infrastructure/ts/icons/PlusIcon";
import { RefreshCwIcon } from "../../../../../infrastructure/ts/icons/RefreshCwIcon";
import { UploadIcon } from "../../../../../infrastructure/ts/icons/UploadIcon";
import { XIcon } from "../../../../../infrastructure/ts/icons/XIcon";
import type { UsageEvent } from "../../../client/ts";
import {
  listUsageEventsApiUsageEventsGetOptions,
  listUsageEventsApiUsageEventsGetQueryKey,
  reportMeterEventsApiMeterEventsPostMutation,
} from "../../../client/ts/@tanstack/react-query.gen";
import { SubscriptionCell } from "../cells/SubscriptionCell";
import { UsageEventEditor } from "../editors/UsageEventEditor";

const columnDefs: ColDef<UsageEvent>[] = [
  {
    field: "created_at",
    headerName: "Created At",
    cellDataType: "dateTimeString",
    width: 250,
    sort: "desc",
  },
  {
    field: "id",
    headerName: "Usage Event ID",
    width: 250,
  },
  {
    headerName: "Subscription",
    field: "subscription_id",
    width: 250,
    cellRenderer: ({ value }: ICellRendererParams<UsageEvent, string>) => (
      <SubscriptionCell subscriptionId={value} />
    ),
  },
  {
    field: "subscription_id",
    headerName: "Subscription ID",
    width: 250,
    hide: true,
  },
  {
    field: "email",
    headerName: "Email",
    width: 250,
  },
  {
    field: "metric",
    headerName: "Metric",
    width: 250,
  },
];

function UsageEventTable({ theme }: { theme: Theme }) {
  const [isEditorOpen, setIsEditorOpen] = useState(false);

  const [reportMeterEventsStatus, setReportMeterEventsStatus] = useState<
    "idle" | "pending" | "success" | "error"
  >("idle");

  const queryClient = useQueryClient();

  const {
    data: usageEvents,
    refetch,
    isFetching,
  } = useSuspenseQuery({
    ...listUsageEventsApiUsageEventsGetOptions(),
    refetchInterval: 30000,
    refetchOnMount: false,
  });

  const { mutate: reportMeterEvents } = useMutation({
    ...reportMeterEventsApiMeterEventsPostMutation(),
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: listUsageEventsApiUsageEventsGetQueryKey(),
      });
      setReportMeterEventsStatus("success");
      setTimeout(() => setReportMeterEventsStatus("idle"), 3000);
    },
    onError: () => {
      setReportMeterEventsStatus("error");
      setTimeout(() => setReportMeterEventsStatus("idle"), 3000);
    },
  });

  const handleAdd = useCallback(() => {
    setIsEditorOpen(true);
  }, []);

  const handleReportMeterEvents = useCallback(() => {
    setReportMeterEventsStatus("pending");
    reportMeterEvents({});
  }, [reportMeterEvents]);

  return (
    <>
      <Flex direction="column" style={{ flex: 1, height: "100%" }}>
        <div style={{ flex: 1, minHeight: 0 }}>
          <AgGridReact
            theme={theme}
            rowData={usageEvents}
            columnDefs={columnDefs}
            defaultColDef={{
              sortable: true,
              filter: true,
              floatingFilter: true,
              resizable: true,
            }}
            getRowId={(params: GetRowIdParams<UsageEvent>) => params.data.id}
            sideBar={{
              toolPanels: ["columns", "filters"],
            }}
            animateRows={true}
            cellSelection={true}
            enableCharts={true}
            enableCellTextSelection
            ensureDomOrder
            suppressNoRowsOverlay={true}
          />
        </div>
        <Flex
          p="2"
          justify="end"
          gap="2"
          style={{
            borderTop: "1px solid var(--gray-6)",
            backgroundColor: "var(--gray-2)",
          }}
        >
          <Button
            size="1"
            variant="soft"
            color={
              reportMeterEventsStatus === "success"
                ? "green"
                : reportMeterEventsStatus === "error"
                  ? "red"
                  : undefined
            }
            onClick={handleReportMeterEvents}
            loading={reportMeterEventsStatus === "pending"}
            style={{ width: 180 }}
          >
            {reportMeterEventsStatus === "success" ? (
              <CheckIcon size={14} />
            ) : reportMeterEventsStatus === "error" ? (
              <XIcon size={14} />
            ) : (
              <>
                <UploadIcon size={14} />
                Report Meter Events
              </>
            )}
          </Button>
          <Button
            size="1"
            variant="soft"
            onClick={() => refetch()}
            loading={isFetching}
            style={{ width: 180 }}
          >
            <RefreshCwIcon size={14} />
            Refresh Usage Events
          </Button>
          <Button
            size="1"
            variant="soft"
            onClick={handleAdd}
            style={{ width: 180 }}
          >
            <PlusIcon size={14} />
            Create Usage Event
          </Button>
        </Flex>
      </Flex>
      <UsageEventEditor
        isOpen={isEditorOpen}
        onClose={() => setIsEditorOpen(false)}
      />
    </>
  );
}

export default UsageEventTable;

CREATE TABLE accounts (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    domains TEXT[] NOT NULL DEFAULT '{}',
    members TEXT[] NOT NULL DEFAULT '{}',
    name TEXT NOT NULL,
    owner TEXT NOT NULL,
    priority INTEGER NOT NULL DEFAULT 0,
    stripe_customer_id TEXT NOT NULL
);

CREATE INDEX accounts_domains_idx ON accounts USING GIN (domains);
CREATE INDEX accounts_members_idx ON accounts USING GIN (members);
CREATE UNIQUE INDEX accounts_name_idx ON accounts (name);
CREATE UNIQUE INDEX accounts_stripe_customer_id_idx ON accounts (stripe_customer_id)
    WHERE stripe_customer_id != '';

CREATE TABLE prices (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    amount INTEGER NOT NULL DEFAULT 0,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    currency TEXT NOT NULL DEFAULT 'usd',
    description TEXT NOT NULL DEFAULT '',
    stripe_price_id TEXT NOT NULL,
    stripe_product_id TEXT NOT NULL
);

CREATE UNIQUE INDEX prices_stripe_price_id_idx ON prices (stripe_price_id);
CREATE INDEX prices_stripe_product_id_idx ON prices (stripe_product_id);

CREATE TABLE quotas (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    hard_limit INTEGER CHECK (hard_limit IS NULL OR hard_limit > 0),
    is_active BOOLEAN NOT NULL DEFAULT true,
    metric TEXT NOT NULL,
    price_id UUID NOT NULL REFERENCES prices (id) ON DELETE CASCADE,
    soft_limit INTEGER CHECK (soft_limit IS NULL OR soft_limit > 0),

    CONSTRAINT quotas_price_metric_unique UNIQUE (price_id, metric),
    CONSTRAINT quotas_limits_valid CHECK (
        soft_limit IS NULL OR hard_limit IS NULL OR hard_limit > soft_limit
    )
);

CREATE INDEX quotas_price_id_idx ON quotas (price_id);

CREATE TABLE subscriptions (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    account_id UUID NOT NULL REFERENCES accounts (id) ON DELETE CASCADE,
    billing_periods JSONB NOT NULL DEFAULT '[]',
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    price_id UUID NOT NULL REFERENCES prices (id) ON DELETE CASCADE,
    status TEXT NOT NULL DEFAULT 'active',
    stripe_subscription_id TEXT NOT NULL,
    stripe_subscription_item_id TEXT NOT NULL
);

CREATE INDEX subscriptions_account_id_idx ON subscriptions (account_id);
CREATE INDEX subscriptions_price_id_idx ON subscriptions (price_id);
CREATE INDEX subscriptions_status_idx ON subscriptions (status);
CREATE INDEX subscriptions_stripe_subscription_id_idx ON subscriptions (stripe_subscription_id);
CREATE UNIQUE INDEX subscriptions_stripe_subscription_item_id_idx ON subscriptions (stripe_subscription_item_id);

CREATE TABLE upgrades (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    current_price_id UUID REFERENCES prices (id) ON DELETE CASCADE,
    is_active BOOLEAN NOT NULL DEFAULT true,
    upgrade_price_id UUID NOT NULL REFERENCES prices (id) ON DELETE CASCADE,

    CONSTRAINT upgrades_prices_unique UNIQUE (current_price_id, upgrade_price_id),
    CONSTRAINT upgrades_prices_different CHECK (current_price_id IS NULL OR current_price_id != upgrade_price_id)
);

CREATE INDEX upgrades_current_price_id_idx ON upgrades (current_price_id);
CREATE INDEX upgrades_upgrade_price_id_idx ON upgrades (upgrade_price_id);
CREATE INDEX upgrades_is_active_idx ON upgrades (is_active);

CREATE TABLE usage_events (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    email TEXT NOT NULL,
    metric TEXT NOT NULL,
    subscription_id UUID NOT NULL REFERENCES subscriptions (id) ON DELETE CASCADE
);

CREATE INDEX usage_events_created_at_idx ON usage_events (created_at);
CREATE INDEX usage_events_email_idx ON usage_events (email);
CREATE INDEX usage_events_metric_idx ON usage_events (metric);
CREATE INDEX usage_events_subscription_id_idx ON usage_events (subscription_id);

import dataclasses
from collections.abc import Callable
from typing import TypeAlias

import asyncache

from server.billing.api import Metric, UsageEvent
from server.billing.service.settings import load_settings

# the value of a meter given usage as of a moment in time
Measure: TypeAlias = Callable[[list[UsageEvent]], int]


@dataclasses.dataclass(frozen=True, kw_only=True)
class Meter:
    """A billable aggregation of usage events."""

    event_name: str
    measure: Measure

    @property
    def display_name(
        self,
    ) -> str:
        return self.measure.__name__.replace("_", " ").title()


# all registered meters
_METERS: list[Meter] = []


def meter() -> Callable[[Measure], Measure]:
    """Decorator that registers an aggregation as a meter.

    :return: Decorator.
    """

    def decorator(measure: Measure, /) -> Measure:
        meter = Meter(
            event_name=measure.__name__,
            measure=measure,
        )

        _METERS.append(meter)

        return measure

    return decorator


@meter()
def active_softlight_users_v1(
    usage_events: list[UsageEvent],
) -> int:
    """Count the number of unique users that have generated at least one revision.

    :return: Number of active Softlight users.
    """
    return len(
        {
            usage_event.email
            for usage_event in usage_events
            if usage_event.metric == Metric.revisions_generated
        },
    )


@asyncache.cached(cache={})
async def load_meters() -> list[Meter]:
    settings = load_settings()

    stripe_meters = await settings.stripe_client.v1.billing.meters.list_async()

    stripe_meters_by_event_name = {
        stripe_meter.event_name: stripe_meter
        async for stripe_meter in stripe_meters.auto_paging_iter()
    }

    for meter in _METERS:
        stripe_meter = stripe_meters_by_event_name.get(meter.event_name)

        if stripe_meter is None:
            await settings.stripe_client.v1.billing.meters.create_async(
                {
                    "display_name": meter.display_name,
                    "event_name": meter.event_name,
                    "default_aggregation": {
                        "formula": "last",
                    },
                    "customer_mapping": {
                        "event_payload_key": "stripe_customer_id",
                        "type": "by_id",
                    },
                    "value_settings": {
                        "event_payload_key": "value",
                    },
                },
            )
        elif stripe_meter.display_name != meter.display_name:
            await settings.stripe_client.v1.billing.meters.update_async(
                stripe_meter.id,
                {
                    "display_name": meter.display_name,
                },
            )

    return _METERS

import datetime
from typing import Self

import pydantic


class Period(pydantic.BaseModel):
    """A time interval."""

    starts_at: pydantic.AwareDatetime
    ends_at: pydantic.AwareDatetime

    @pydantic.model_validator(mode="after")
    def _ends_at_is_greater_than_starts_at(
        self,
    ) -> Self:
        if self.ends_at <= self.starts_at:
            raise ValueError("`ends_at` must be greater than `starts_at`")

        return self

    @staticmethod
    def from_timestamps(
        starts_at: float,
        ends_at: float,
    ) -> "Period":
        """Create a period from Unix timestamps.

        :param starts_at: Start of the period as seconds since epoch.
        :param ends_at: End of the period as seconds since epoch.
        :return: Period.
        """
        return Period(
            starts_at=datetime.datetime.fromtimestamp(
                starts_at,
                tz=datetime.UTC,
            ),
            ends_at=datetime.datetime.fromtimestamp(
                ends_at,
                tz=datetime.UTC,
            ),
        )

