import { useState } from "react";
import { Badge, Button, Flex, Tooltip } from "@radix-ui/themes";
import { useSuspenseQuery } from "@tanstack/react-query";
import {
  ColDef,
  GetRowIdParams,
  ICellRendererParams,
  RowClickedEvent,
  Theme,
  ValueFormatterParams,
} from "ag-grid-community";
import { AgGridReact } from "ag-grid-react";

import { PlusIcon } from "../../../../../infrastructure/ts/icons/PlusIcon";
import { RefreshCwIcon } from "../../../../../infrastructure/ts/icons/RefreshCwIcon";
import type { Period, Subscription } from "../../../client/ts";
import { listSubscriptionsApiSubscriptionsGetOptions } from "../../../client/ts/@tanstack/react-query.gen";
import { AccountCell } from "../cells/AccountCell";
import { PriceCell } from "../cells/PriceCell";
import { SubscriptionEditor } from "../editors/SubscriptionEditor";

function formatDate(dateStr: string) {
  return new Date(dateStr).toLocaleDateString();
}

function isCurrentPeriod(period: Period) {
  const now = new Date();
  return new Date(period.starts_at) <= now && new Date(period.ends_at) > now;
}

const statusColors = {
  active: "green",
  trialing: "blue",
  canceled: "gray",
  paused: "bronze",
  past_due: "orange",
  incomplete: "yellow",
  incomplete_expired: "red",
  unpaid: "crimson",
} as const satisfies Record<NonNullable<Subscription["status"]>, string>;

const columnDefs: ColDef<Subscription>[] = [
  {
    field: "created_at",
    headerName: "Created At",
    cellDataType: "dateTimeString",
    width: 250,
    sort: "desc",
  },
  {
    field: "id",
    headerName: "Subscription ID",
    width: 250,
  },
  {
    headerName: "Account",
    field: "account_id",
    width: 250,
    cellRenderer: ({ value }: ICellRendererParams<Subscription, string>) => (
      <AccountCell accountId={value} />
    ),
  },
  {
    field: "account_id",
    headerName: "Account ID",
    width: 250,
    hide: true,
  },
  {
    headerName: "Price",
    field: "price_id",
    width: 250,
    cellRenderer: ({ value }: ICellRendererParams<Subscription, string>) => (
      <PriceCell priceId={value} />
    ),
  },
  {
    field: "price_id",
    headerName: "Price ID",
    width: 250,
    hide: true,
  },
  {
    field: "stripe_subscription_id",
    headerName: "Stripe Subscription ID",
    width: 250,
    cellRenderer: ({ value }: ICellRendererParams<Subscription, string>) =>
      value ? (
        <a
          href={`https://dashboard.stripe.com/subscriptions/${value}`}
          target="_blank"
          rel="noopener noreferrer"
          style={{ color: "var(--accent-11)" }}
          onClick={(e) => e.stopPropagation()}
        >
          {value}
        </a>
      ) : null,
  },
  {
    field: "stripe_subscription_item_id",
    headerName: "Stripe Item ID",
    width: 250,
    cellRenderer: ({
      value,
      data,
    }: ICellRendererParams<Subscription, string>) =>
      value && data?.stripe_subscription_id ? (
        <a
          href={`https://dashboard.stripe.com/subscriptions/${data.stripe_subscription_id}`}
          target="_blank"
          rel="noopener noreferrer"
          style={{ color: "var(--accent-11)" }}
          onClick={(e) => e.stopPropagation()}
        >
          {value}
        </a>
      ) : (
        <span>{value}</span>
      ),
  },
  {
    field: "status",
    headerName: "Status",
    width: 250,
    cellRenderer: ({ value }: ICellRendererParams<Subscription, string>) => {
      const color = statusColors[value as keyof typeof statusColors];
      return <Badge color={color}>{value}</Badge>;
    },
  },
  {
    field: "billing_periods",
    headerName: "Billing Periods",
    width: 250,
    valueFormatter: (params: ValueFormatterParams<Subscription, Period[]>) => {
      const periods = params.value;
      if (!periods || periods.length === 0) return "No billing periods";
      return periods
        .map((p) => {
          const range = `${formatDate(p.starts_at)} → ${formatDate(p.ends_at)}`;
          return isCurrentPeriod(p) ? `${range} (current)` : range;
        })
        .join("; ");
    },
    autoHeight: true,
    wrapText: true,
  },
];

function SubscriptionTable({ theme }: { theme: Theme }) {
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [selectedSubscription, setSelectedSubscription] =
    useState<Subscription | null>(null);

  const {
    data: subscriptions,
    refetch,
    isFetching,
  } = useSuspenseQuery({
    ...listSubscriptionsApiSubscriptionsGetOptions(),
    refetchInterval: 30000,
    refetchOnMount: false,
  });

  const handleRowClick = (event: RowClickedEvent<Subscription>) => {
    setSelectedSubscription(event.data ?? null);
    setIsEditorOpen(true);
  };

  return (
    <>
      <Flex direction="column" style={{ flex: 1, height: "100%" }}>
        <div style={{ flex: 1, minHeight: 0 }}>
          <AgGridReact
            theme={theme}
            rowData={subscriptions}
            columnDefs={columnDefs}
            defaultColDef={{
              sortable: true,
              filter: true,
              floatingFilter: true,
              resizable: true,
            }}
            getRowId={(params: GetRowIdParams<Subscription>) => params.data.id!}
            sideBar={{
              toolPanels: ["columns", "filters"],
            }}
            animateRows={true}
            cellSelection={true}
            enableCharts={true}
            enableCellTextSelection
            ensureDomOrder
            onRowClicked={handleRowClick}
            suppressNoRowsOverlay={true}
          />
        </div>
        <Flex
          p="2"
          justify="end"
          gap="2"
          style={{
            borderTop: "1px solid var(--gray-6)",
            backgroundColor: "var(--gray-2)",
          }}
        >
          <Button
            size="1"
            variant="soft"
            onClick={() => refetch()}
            loading={isFetching}
            style={{ width: 180 }}
          >
            <RefreshCwIcon size={14} />
            Refresh Subscriptions
          </Button>
          <Tooltip content="Subscriptions must be created in Stripe">
            <Button size="1" variant="soft" disabled style={{ width: 180 }}>
              <PlusIcon size={14} />
              Create Subscription
            </Button>
          </Tooltip>
        </Flex>
      </Flex>
      <SubscriptionEditor
        isOpen={isEditorOpen}
        onClose={() => setIsEditorOpen(false)}
        subscription={selectedSubscription}
      />
    </>
  );
}

export default SubscriptionTable;

import { useCallback, useEffect, useState } from "react";
import * as Form from "@radix-ui/react-form";
import {
  Button,
  Callout,
  Dialog,
  Flex,
  IconButton,
  Text,
  TextField,
} from "@radix-ui/themes";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { v4 as uuidv4 } from "uuid";

import { AlertCircleIcon } from "../../../../../infrastructure/ts/icons/AlertCircleIcon";
import { Loader2Icon } from "../../../../../infrastructure/ts/icons/Loader2Icon";
import { PlusIcon } from "../../../../../infrastructure/ts/icons/PlusIcon";
import { SaveIcon } from "../../../../../infrastructure/ts/icons/SaveIcon";
import { Trash2Icon } from "../../../../../infrastructure/ts/icons/Trash2Icon";
import { XIcon } from "../../../../../infrastructure/ts/icons/XIcon";
import type { Account } from "../../../client/ts";
import {
  listAccountsApiAccountsGetQueryKey,
  upsertAccountApiAccountsPutMutation,
} from "../../../client/ts/@tanstack/react-query.gen";

type Props = {
  account: Account | null;
  isOpen: boolean;
  onClose: () => void;
};

function getDefaultAccount(): Account {
  return {
    created_at: new Date().toISOString(),
    id: uuidv4(),
    name: "",
    owner: "",
    priority: 0,
    domains: [],
    members: [],
  };
}

export function AccountEditor({ account, isOpen, onClose }: Props) {
  const queryClient = useQueryClient();

  const [draft, setDraft] = useState(getDefaultAccount());

  const { mutate, reset, isPending, error } = useMutation({
    ...upsertAccountApiAccountsPutMutation(),
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: listAccountsApiAccountsGetQueryKey(),
      });
      onClose();
    },
  });

  useEffect(() => {
    if (isOpen) {
      setDraft(account ?? getDefaultAccount());
      reset();
    }
  }, [account, isOpen, reset]);

  const handleSubmit = useCallback(
    (e: React.FormEvent) => {
      e.preventDefault();
      mutate({
        body: {
          ...draft,
          domains: draft.domains?.filter(Boolean) ?? [],
          members: draft.members?.filter(Boolean) ?? [],
        },
      });
    },
    [draft, mutate],
  );

  const canSubmit = Boolean(draft.name && draft.owner);

  return (
    <Dialog.Root open={isOpen} onOpenChange={(open) => !open && onClose()}>
      <Dialog.Content maxWidth="480px">
        <Dialog.Title>
          {account ? "Edit Account" : "Create Account"}
        </Dialog.Title>

        <Form.Root onSubmit={handleSubmit} onClearServerErrors={reset}>
          <Flex direction="column" gap="4" py="4">
            {error && (
              <Callout.Root color="red" size="1">
                <Callout.Icon>
                  <AlertCircleIcon size={16} />
                </Callout.Icon>
                <Callout.Text style={{ whiteSpace: "pre-wrap" }}>
                  {JSON.stringify(error, null, 2)}
                </Callout.Text>
              </Callout.Root>
            )}

            <Form.Field name="created_at">
              <Form.Label asChild>
                <Text size="2" weight="medium" mb="1">
                  Created At
                </Text>
              </Form.Label>
              <Form.Control asChild>
                <TextField.Root value={draft.created_at} disabled />
              </Form.Control>
            </Form.Field>

            <Form.Field name="id">
              <Form.Label asChild>
                <Text size="2" weight="medium" mb="1">
                  Account ID
                </Text>
              </Form.Label>
              <Form.Control asChild>
                <TextField.Root value={draft.id} disabled />
              </Form.Control>
            </Form.Field>

            <Form.Field name="name">
              <Form.Label asChild>
                <Text size="2" weight="medium" mb="1">
                  Name <Text color="red">*</Text>
                </Text>
              </Form.Label>
              <Form.Control asChild>
                <TextField.Root
                  value={draft.name ?? ""}
                  onChange={(e) => setDraft({ ...draft, name: e.target.value })}
                  disabled={!!account}
                  placeholder="Example, Inc."
                />
              </Form.Control>
            </Form.Field>

            {account?.stripe_customer_id && (
              <Form.Field name="stripe_customer_id">
                <Form.Label asChild>
                  <Text size="2" weight="medium" mb="1">
                    Stripe Customer ID
                  </Text>
                </Form.Label>
                <Form.Control asChild>
                  <TextField.Root value={account.stripe_customer_id} disabled />
                </Form.Control>
              </Form.Field>
            )}

            <Form.Field name="owner">
              <Form.Label asChild>
                <Text size="2" weight="medium" mb="1">
                  Owner <Text color="red">*</Text>
                </Text>
              </Form.Label>
              <Form.Control asChild>
                <TextField.Root
                  value={draft.owner}
                  onChange={(e) =>
                    setDraft({ ...draft, owner: e.target.value })
                  }
                  placeholder="user@example.com"
                />
              </Form.Control>
            </Form.Field>

            <Form.Field name="priority">
              <Form.Label asChild>
                <Text size="2" weight="medium" mb="1">
                  Priority
                </Text>
              </Form.Label>
              <Form.Control asChild>
                <TextField.Root
                  defaultValue={draft.priority?.toString() ?? "0"}
                  key={draft.id}
                  onBlur={(e) => {
                    const parsed = parseInt(e.target.value, 10);
                    setDraft({
                      ...draft,
                      priority: Number.isNaN(parsed) ? 0 : parsed,
                    });
                  }}
                  type="number"
                />
              </Form.Control>
            </Form.Field>

            <Flex direction="column" gap="2">
              <Text size="2" weight="medium">
                Domains
              </Text>
              {(draft.domains ?? []).map((value, index) => (
                <Flex key={index} gap="2" align="center">
                  <TextField.Root
                    value={value}
                    onChange={(e) => {
                      const updated = [...(draft.domains ?? [])];
                      updated[index] = e.target.value;
                      setDraft({ ...draft, domains: updated });
                    }}
                    placeholder="example.com"
                    style={{ flex: 1 }}
                  />
                  <IconButton
                    type="button"
                    variant="ghost"
                    color="gray"
                    onClick={() =>
                      setDraft({
                        ...draft,
                        domains: (draft.domains ?? []).filter(
                          (_, i) => i !== index,
                        ),
                      })
                    }
                  >
                    <XIcon size={16} />
                  </IconButton>
                </Flex>
              ))}
              <Button
                type="button"
                variant="ghost"
                size="1"
                style={{ alignSelf: "flex-start" }}
                onClick={() =>
                  setDraft({
                    ...draft,
                    domains: [...(draft.domains ?? []), ""],
                  })
                }
              >
                <PlusIcon size={14} /> Add domain
              </Button>
            </Flex>

            <Flex direction="column" gap="2">
              <Text size="2" weight="medium">
                Members
              </Text>
              {(draft.members ?? []).map((value, index) => (
                <Flex key={index} gap="2" align="center">
                  <TextField.Root
                    value={value}
                    onChange={(e) => {
                      const updated = [...(draft.members ?? [])];
                      updated[index] = e.target.value;
                      setDraft({ ...draft, members: updated });
                    }}
                    placeholder="user@example.com"
                    style={{ flex: 1 }}
                  />
                  <IconButton
                    type="button"
                    variant="ghost"
                    color="gray"
                    onClick={() =>
                      setDraft({
                        ...draft,
                        members: (draft.members ?? []).filter(
                          (_, i) => i !== index,
                        ),
                      })
                    }
                  >
                    <XIcon size={16} />
                  </IconButton>
                </Flex>
              ))}
              <Button
                type="button"
                variant="ghost"
                size="1"
                style={{ alignSelf: "flex-start" }}
                onClick={() =>
                  setDraft({
                    ...draft,
                    members: [...(draft.members ?? []), ""],
                  })
                }
              >
                <PlusIcon size={14} /> Add member
              </Button>
            </Flex>
          </Flex>

          <Flex gap="3" justify="end" mt="4">
            <Dialog.Close>
              <Button
                variant="soft"
                color="gray"
                type="button"
                style={{ width: 100 }}
              >
                <Trash2Icon size={14} />
                Cancel
              </Button>
            </Dialog.Close>
            <Form.Submit asChild>
              <Button
                type="submit"
                disabled={!canSubmit || isPending}
                style={{ width: 100 }}
              >
                {isPending ? (
                  <Loader2Icon size={16} className="animate-spin" />
                ) : (
                  <>
                    <SaveIcon size={14} />
                    Save
                  </>
                )}
              </Button>
            </Form.Submit>
          </Flex>
        </Form.Root>
      </Dialog.Content>
    </Dialog.Root>
  );
}

