import { queryOptions } from "@tanstack/react-query";
import {
  mockAccounts,
  mockPrices,
  mockQuotas,
  mockSubscriptions,
  mockUpgrades,
  mockUsageEvents,
  mockUsages,
} from "./mockData";

const delay = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));

export const accountsQueryOptions = queryOptions({
  queryKey: ["accounts"],
  queryFn: async () => {
    await delay(300);
    return mockAccounts;
  },
  staleTime: 30000,
});

export const pricesQueryOptions = queryOptions({
  queryKey: ["prices"],
  queryFn: async () => {
    await delay(300);
    return mockPrices;
  },
  staleTime: 30000,
});

export const subscriptionsQueryOptions = queryOptions({
  queryKey: ["subscriptions"],
  queryFn: async () => {
    await delay(300);
    return mockSubscriptions;
  },
  staleTime: 30000,
});

export const quotasQueryOptions = queryOptions({
  queryKey: ["quotas"],
  queryFn: async () => {
    await delay(300);
    return mockQuotas;
  },
  staleTime: 30000,
});

export const upgradesQueryOptions = queryOptions({
  queryKey: ["upgrades"],
  queryFn: async () => {
    await delay(300);
    return mockUpgrades;
  },
  staleTime: 30000,
});

export const usageEventsQueryOptions = queryOptions({
  queryKey: ["usage-events"],
  queryFn: async () => {
    await delay(300);
    return mockUsageEvents;
  },
  staleTime: 30000,
});

export const usagesQueryOptions = queryOptions({
  queryKey: ["usages"],
  queryFn: async () => {
    await delay(300);
    return mockUsages;
  },
  staleTime: 30000,
});

